mapper.insert:
/* QUERYID(push.insertPushSndResult ::  푸쉬발송처리결과 등록) */

	SELECT TO_CHAR(SYSTIMESTAMP, 'YYYYMMDDHH24MISSFF') || ROUND(DBMS_RANDOM.VALUE () * 100000) AS PUSH_SND_PROC_SNO
	FROM DUAL

INSERT INTO NMCP_PUSH_SND_PROC_RST_LIST (
	PUSH_SND_PROC_SNO	/* 푸쉬발송처리일련번호 */
	, PUSH_SND_SET_SNO	/* 푸쉬발송설정일련번호 */
	, TOT_CNT			/* 총건수 */
	, SUCCESS_CNT		/* 성공건수 */
	, FAIL_CNT			/* 실패건수 */
	, SND_PROC_DT		/* 발송처리일자 */
	, SYS_REG_IP
	, SYS_REG_ID		/* 시스템등록아이디 */
	, SYS_REG_DTIME		/* 시스템등록일시 */
	, SYS_CHG_IP
	, SYS_CHG_DTIME		/* 시스템수정아이디 */
	, SYS_CHG_ID		/* 시스템수정일시 */
) VALUES (
	#{pushSndProcSno}
	, #{pushSndSetSno}
	, #{totCnt}
	, #{successCnt}
	, #{failCnt}
	, SYSDATE
	, #{sysRegIp}
	, #{sysRegId}
	, SYSDATE
	, #{sysRegIp}
	, SYSDATE
	, #{sysRegId}
)

/* QUERYID(push.insertPushTargetUserFind :: 푸쉬발송 대상자 추출 등록) */ INSERT INTO NMCP_PUSH_SND_PROC_TRGT_LIST ( PUSH_SND_PROC_SNO /*푸쉬발송처리일련번호*/ ,PUSH_SND_SET_SNO /*실시간발송이력위해관리*/ ,USERID /*고객id*/ ,CELL_NO /*핸드폰번호*/ ,APP_OS_TP /*A:Android, I:IOS*/ ,PROC_ST /*코드값(Y : 발송 / N : 대기 / X : 오류)*/ ,APP_OS_VER /*단말기OS버전*/ ,SND_PROC_DT /*발송처리일자*/ ,SERVER_COLCT_YN /*코드값(Y : 수집 / N : 미수집) / 서버에서 결과값을 등록*/ ,APP_COLCT_YN /*코드값(Y : 수집 / N : 미수집) / 앱에서 연동API를 통한 결과값을 등록*/ ,PUSH_ICON_TP /* 푸쉬아이콘유형*/ ,SND_TITLE /*발송제목*/ ,SND_MSG /*문구/HTML*/
,PUSH_IMG_URL
,PUSH_IMG_NM /*NAS 이미지 명*/
,LINK_DIV /*A:App실행, O:외부링크*/
,LINK_URL /* 링크URL*/
,SND_CNT /*default: 1 , 최대 5회 재발송*/ ,SND_TEST_YN /*코드값(Y : 테스트발송 / N : 실제발송)*/ ,TGT_SERVER /*타겟서버*/ ,SYS_REG_IP ,SYS_REG_DTIME ,SYS_REG_ID ,SYS_CHG_IP ,SYS_CHG_DTIME ,SYS_CHG_ID ) SELECT #{pushSndSetSno} /* 푸쉬발송설정일련번호 */ , #{pushSndProcSno} /* 푸쉬발송처리일련번호 */ , A.USERID /* 회원번호 */ , A.MOBILE_NO /* 핸드폰번호 */ , A.OS /* 단말기OS유형 */ , #{procSt} /* 처리상태 */ , A.APP_OS_VER , SYSDATE , #{serverColctYn} /* 서버수집여부 */ , #{appColctYn} /* 앱수집여부 */ , #{pushIconTp} /* 푸쉬아이콘 */ , #{sndTitle} , #{sndMsg} /* 발송메시지 */
, #{pushImgUrl} /* 푸쉬 이미지 */
, #{pushImgNm} /* 푸쉬 이미지 */
, #{linkDiv} /* 링크구분 */
, #{linkUrl} /* 링크URL */
, #{sndCnt} /* 발송횟수 */ , #{sndTestYn} /* 발송테스트여부 */ , 'admin' , #{sysRegIp} /* 시스템등록아이디 */ , SYSDATE /* 시스템등록일시 */ , #{sysRegId} /* 시스템등록아이디 */ , #{sysRegIp} /* 시스템수정아이디 */ , SYSDATE /* 시스템수정일시 */ , #{sysRegId} /* 시스템수정아이디 */ FROM ( SELECT TMMB.USERID /* 회원넘버 */ , TMMB.MOBILE_NO /* 휴대폰번호 */ , TUMAI.OS /* APP 설치버전 */ , TUMAI.UDID ,CASE WHEN INSTR(APP_OS_VER,'.',1,2) > 0 THEN SUBSTR(APP_OS_VER,1,INSTR(APP_OS_VER,'.',1,2)-1) WHEN INSTR(APP_OS_VER,'.',1,1) = 0 THEN APP_OS_VER || '.0' ELSE APP_OS_VER END AS APP_OS_VER ,TUMAI.VERSION FROM MCP_USER TMMB LEFT JOIN ( SELECT UUID, UDID, USER_ID,LAST_ACCESS_DT,SEND_YN,OS,VERSION, APP_OS_VER FROM ( SELECT UUID, UDID, USER_ID,LAST_ACCESS_DT,SEND_YN,OS,VERSION, APP_OS_VER, RANK() OVER (PARTITION BY USER_ID ORDER BY UP_DT DESC) AS RNK FROM NMCP_USR_APP_INFO WHERE UDID IS NOT NULL ) WHERE RNK = '1' ) TUMAI ON TMMB.USERID = TUMAI.USER_ID WHERE REVOCATION_DATE IS NULL /* 탈퇴일자 */ AND TUMAI.SEND_YN = 'Y'
/* 단말기OS유형, 단말기OS버전, APP 설치버전 */ AND TUMAI.OS = 'A'
AND TUMAI.APP_OS_VER IN (#{andOsVerLst2})
AND TUMAI.VERSION IN (#{andInstlVerLst2})
/* 단말기OS유형, 단말기OS버전, APP 설치버전 */ AND TUMAI.OS = 'I'
AND TUMAI.APP_OS_VER IN (#{iosOsVerLst2})
AND TUMAI.VERSION IN (#{iosInstlVerLst2})
/* 단말기OS유형, 단말기OS버전, APP 설치버전 */
AND ( (TUMAI.OS = 'A' AND TUMAI.APP_OS_VER IN (#{andOsVerLst2}) AND TUMAI.VERSION IN (#{andInstlVerLst2}) ) OR ( TUMAI.OS = 'I' AND TUMAI.APP_OS_VER IN (#{iosOsVerLst2}) AND TUMAI.VERSION IN (#{iosInstlVerLst2}) ) )
/* 회원구분코드 */ AND TMMB.USER_DIVISION =#{custDivLst}
)A

mapper.update:
/* QUERYID(pushBatch.updatePushSndResult : 푸쉬 발송 결과 업데이트) */ UPDATE NMCP_PUSH_SND_PROC_RST_LIST SET SYS_CHG_ID = #{sysModId} /* 시스템 수정 아이디 */ , SYS_CHG_DTIME = SYSDATE /* 시스템 수정 일시 */
, TOT_CNT = #{totCnt} /* 총건수 */
WHERE PUSH_SND_PROC_SNO = #{pushSndProcSno} /* 푸쉬발송처리일련번호 */ AND PUSH_SND_SET_SNO = #{pushSndSetSno} /* 푸쉬발송설정일련번호 */
